import React, { useState } from 'react';
import { useI18n } from '../i18n/I18nContext';

const WaitingRoom = ({ gameId, roomPassword, handleBackToMenu, timeLimit }) => {
    const { t } = useI18n();
    const [copied, setCopied] = useState(null);

    const copyWith = (text, label) => {
        navigator.clipboard?.writeText(text).then(() => {
            setCopied(label);
            setTimeout(() => setCopied(null), 2000);
        }).catch(() => {});
    };

    return (
        <div className="max-w-sm mx-auto pt-6 text-center space-y-5 animate-fade-in">
            <div className="text-6xl animate-bounce" style={{ animationDuration: '2s' }}>⏳</div>
            <div>
                <h2 className="text-xl font-bold">{t('waiting.title')}</h2>
                <p className="text-slate-400 text-sm mt-1">{t('waiting.shareHint')}</p>
            </div>
            <div className="bg-gradient-to-br from-slate-800 to-slate-900 border-2 border-yellow-400/80 rounded-2xl px-6 py-5 shadow-lg shadow-yellow-900/20 relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-r from-yellow-500/5 via-transparent to-yellow-500/5" />
                <div className="relative">
                    <p className="text-[0.6rem] text-yellow-400 uppercase tracking-widest mb-1.5 font-bold">{t('waiting.roomCode')}</p>
                    <p className="text-4xl sm:text-5xl font-black font-mono text-yellow-300 tracking-widest drop-shadow-lg">{gameId}</p>
                    {roomPassword && (
                        <p className="text-xs text-orange-300 mt-3 bg-orange-500/10 rounded-lg py-1 px-3 inline-block">🔒 PIN: <span className="font-mono font-bold">{roomPassword}</span></p>
                    )}
                    {timeLimit && (
                        <p className="text-xs text-blue-300 mt-2">⏱️ {Math.round(timeLimit / 60)} {t('waiting.minGame')}</p>
                    )}
                </div>
            </div>
            <div className="flex gap-2 justify-center flex-wrap">
                <button
                    onClick={() => copyWith(gameId, 'code')}
                    className={`px-5 py-2.5 text-sm rounded-xl transition font-semibold ${copied === 'code' ? 'bg-green-600 text-white shadow-green-900/30 shadow-md' : 'bg-slate-700 hover:bg-slate-600 text-slate-200 hover:scale-[1.02]'}`}
                >
                    {copied === 'code' ? t('waiting.copied') : t('waiting.copyCode')}
                </button>
                <button
                    onClick={() => {
                        const path = roomPassword ? `${gameId}/${roomPassword}` : gameId;
                        const url = `${window.location.origin}/${path}`;
                        copyWith(url, 'link');
                    }}
                    className={`px-5 py-2.5 text-sm rounded-xl transition font-semibold ${copied === 'link' ? 'bg-green-600 text-white shadow-green-900/30 shadow-md' : 'bg-blue-600 hover:bg-blue-500 text-white hover:scale-[1.02]'}`}
                >
                    {copied === 'link' ? t('waiting.copied') : `${t('waiting.copyLink')}${roomPassword ? ` ${t('waiting.plusPin')}` : ''}`}
                </button>
            </div>
            <div className="flex justify-center gap-2">
                {[0, 150, 300].map(d => (
                    <span key={d} className="w-2.5 h-2.5 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: `${d}ms` }} />
                ))}
            </div>
            <button
                onClick={handleBackToMenu}
                className="mt-4 px-6 py-2 bg-red-900/50 hover:bg-red-800/60 text-red-300 text-sm font-semibold rounded-xl transition border border-red-700/50"
            >
                {t('waiting.leaveRoom')}
            </button>
        </div>
    );
};

export default WaitingRoom;
